Histórico da conversa: {{ $('Buscar Estado').item.json.rows && $('Buscar Estado').item.json.rows[0] ? $('Buscar Estado').item.json.rows[0].historico : '[]' }}
Nova mensagem do cliente: {{ $('Webhook Pedido').item.json.body.mensagem }}

Colete: itens_pedido (produto_id, nome, quantidade, preco_unitario), endereco_entrega, forma_pagamento (pix/dinheiro/cartao_credito), observacoes.

Retorne SOMENTE JSON válido:
{"resposta": "...", "pedido_completo": true|false, "dados_coletados": {"itens_pedido": [], "endereco_entrega": "", "forma_pagamento": "", "observacoes": ""}}

parameters.jsCode:
const iaRaw = $('IA Coleta Pedido').item.json.message.content;
const ia = JSON.parse(iaRaw);

const estadoRows = $('Buscar Estado').item.json.rows || [];
const estadoRow = estadoRows[0] || {};
const estadoAnterior = JSON.parse(estadoRow.dados_parciais || '{}');
const historicoAnterior = JSON.parse(estadoRow.historico || '[]');
const turnos = (estadoRow.turnos || 0) + 1;

const telefone = $('Webhook Pedido').item.json.body.telefone;
const mensagem = $('Webhook Pedido').item.json.body.mensagem;
const nome_cliente = $('Webhook Pedido').item.json.body.nome_cliente || '';

// Merge dados coletados com estado anterior
const dadosColetados = ia.dados_coletados || {};
const dadosMergados = {
  itens_pedido: dadosColetados.itens_pedido?.length ? dadosColetados.itens_pedido : (estadoAnterior.itens_pedido || []),
  endereco_entrega: dadosColetados.endereco_entrega || estadoAnterior.endereco_entrega || '',
  forma_pagamento: dadosColetados.forma_pagamento || estadoAnterior.forma_pagamento || '',
  observacoes: dadosColetados.observacoes || estadoAnterior.observacoes || ''
};

const historicoNovo = [...historicoAnterior, { role: 'user', content: mensagem }, { role: 'assistant', content: ia.resposta }];

const limite_atingido = turnos >= 8;

return [{
  json: {
    telefone,
    nome_cliente,
    resposta: ia.resposta,
    pedido_completo: ia.pedido_completo === true,
    limite_atingido,
    dados_parciais: dadosMergados,
    historico: historicoNovo,
    turnos,
    row_id: estadoRow.id || null
  }
}];

const dados = $input.first().json;
const baseUrl = 'https://n8n.evoapi.shop/api/v1/data-tables/jQ5Ol9nLxqo1fUH4/rows';
const apiKey = $vars.N8N_API_KEY;

const body = {
  telefone: dados.telefone,
  historico: JSON.stringify(dados.historico),
  dados_parciais: JSON.stringify(dados.dados_parciais),
  turnos: dados.turnos,
  atualizado_em: new Date().toISOString()
};

if (dados.row_id) {
  // Update existente
  await $helpers.httpRequest({
    method: 'PATCH',
    url: `${baseUrl}/${dados.row_id}`,
    headers: { 'X-N8N-API-KEY': apiKey, 'Content-Type': 'application/json' },
    body: JSON.stringify(body)
  });
} else {
  // Insert novo
  await $helpers.httpRequest({
    method: 'POST',
    url: baseUrl,
    headers: { 'X-N8N-API-KEY': apiKey, 'Content-Type': 'application/json' },
    body: JSON.stringify(body)
  });
}

return [$input.first()];

